package manifest

import (
	"errors"
	"fmt"
	"os"
	"regexp"
	"strings"

	"github.com/goccy/go-yaml"
)

type LoadOptions struct {
	// NonInteractive enforces the CI-safe invariant: if `canonical.commit` is
	// set, `trusted_sha` must also be set.
	NonInteractive bool
}

var (
	ErrInvalidManifest = errors.New("invalid manifest")

	reHex40 = regexp.MustCompile(`\A[0-9a-f]{40}\z`)
)

func LoadFile(path string, opts LoadOptions) (*Manifest, error) {
	b, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	m, err := LoadBytes(b, opts)
	if err != nil {
		return nil, err
	}
	return m, nil
}

func LoadBytes(src []byte, opts LoadOptions) (*Manifest, error) {
	var m Manifest
	if err := yaml.UnmarshalWithOptions(
		src,
		&m,
		yaml.DisallowUnknownField(),
		yaml.AllowFieldPrefixes("x-"),
	); err != nil {
		return nil, fmt.Errorf("%w: %s", ErrInvalidManifest, yaml.FormatError(err, false, true))
	}

	if err := Validate(&m, opts); err != nil {
		// Prefer returning the underlying error wrapped by ErrInvalidManifest
		// so callers can recognize "manifest is invalid" as a single class.
		return nil, fmt.Errorf("%w: %w", ErrInvalidManifest, err)
	}
	return &m, nil
}

func Validate(m *Manifest, opts LoadOptions) error {
	if m == nil {
		return fmt.Errorf("manifest is nil")
	}

	if m.Version == 0 {
		// Default to v1 for the greenfield phase. Once aienvs ships, this
		// should become required.
		m.Version = 1
	}
	if m.Version != 1 {
		return fmt.Errorf("unsupported manifest version %d (want 1)", m.Version)
	}

	// Canonical source 1:1 invariant: exactly one of url/local_path.
	hasURL := strings.TrimSpace(m.Canonical.URL) != ""
	hasLocal := strings.TrimSpace(m.Canonical.LocalPath) != ""
	switch {
	case hasURL && hasLocal:
		return fmt.Errorf("canonical source must set exactly one of url or local_path (got both)")
	case !hasURL && !hasLocal:
		return fmt.Errorf("canonical source must set exactly one of url or local_path (got neither)")
	}

	commit := strings.TrimSpace(m.Canonical.Commit)
	trusted := strings.TrimSpace(m.TrustedSHA)

	if trusted != "" && commit == "" {
		return fmt.Errorf("trusted_sha is set but canonical.commit is empty (no floating-with-pin hybrid)")
	}
	if commit != "" && !reHex40.MatchString(commit) {
		return fmt.Errorf("canonical.commit must be 40 lowercase hex (got %q)", commit)
	}
	if trusted != "" && !reHex40.MatchString(trusted) {
		return fmt.Errorf("trusted_sha must be 40 lowercase hex (got %q)", trusted)
	}
	if opts.NonInteractive && commit != "" && trusted == "" {
		return fmt.Errorf("non-interactive mode requires trusted_sha when canonical.commit is set")
	}
	if commit != "" && trusted != "" && commit != trusted {
		return fmt.Errorf("trusted_sha must mirror canonical.commit (commit=%q trusted_sha=%q)", commit, trusted)
	}

	switch m.Scope {
	case "", "user", "project", "global":
	default:
		return fmt.Errorf("scope must be one of user|project|global (got %q)", m.Scope)
	}

	return nil
}

// Package fsroot provides the safe-filesystem primitives that every other
// aienvs package must use to read and write paths inside a user workspace.
//
// The package wraps Go 1.25's [os.Root] with four capabilities that the rest
// of aienvs depends on:
//
//  1. Containment. All operations are scoped to a single directory handle
//     and cannot escape it through symlinks, "..", absolute paths, or
//     Windows device namespaces. This is enforced by [os.Root] itself.
//
//  2. Atomic writes via [Root.StagedWrite]. Writes go through a uniquely
//     named sibling temp file, fsync the file (and best-effort fsync the
//     parent directory), then rename atomically. The temp file is cleaned
//     up on every error path.
//
//  3. Advisory cross-filesystem detection via [SameFilesystem]. The
//     authoritative cross-FS signal is the error returned by
//     [os.Root.Rename] (EXDEV / ERROR_NOT_SAME_DEVICE); [SameFilesystem] is
//     only used to enrich error messages, never to gate operations. See
//     plan decision #20.
//
//  4. Irregular-file refusal via [Root.DetectReparsePoint]. Reparse points,
//     device files, sockets, and named pipes surface as
//     [fs.ModeIrregular] after [os.Root]'s own filtering. aienvs refuses
//     to write through them as defense-in-depth.
//
// # Scoping
//
// Per plan decision #6, callers typically open a [Root] at the parent of
// the target's reserved prefix (e.g. "<workspace>/.claude/") rather than
// at the reserved prefix itself. This lets a single [Root] scope both
// legs of the atomic two-rename swap in unit 13 without the root handle
// blocking its own rename on Windows.
//
// # Non-goals
//
// This package intentionally does not abstract the filesystem behind an
// interface. Tests that need a fake filesystem should either operate
// against a real [testing.T.TempDir] (preferred for anything touching
// rename semantics) or sit at a higher layer that uses fsroot only
// through its exported functions.
package fsroot

package fsroot

import (
	"crypto/rand"
	"encoding/hex"
	"errors"
	"fmt"
	"io/fs"
	"os"
	"path"
	"strings"
)

// StagedWrite atomically writes data to relPath inside the root.
//
// The write proceeds as: create a uniquely named sibling temp file with
// O_CREATE|O_WRONLY|O_EXCL|O_NOFOLLOW; write data; fsync the file; close;
// rename the temp file over relPath; best-effort fsync the parent
// directory.
//
// All operations are scoped to the root via [os.Root], so:
//   - relPath cannot escape the root (ValidateRelPath + os.Root).
//   - The temp file is always a sibling of the final target, so the
//     rename is by construction intra-directory and therefore
//     cross-filesystem is structurally impossible under normal
//     configurations. We still translate [EXDEV] / [ERROR_NOT_SAME_DEVICE]
//     into [ErrCrossVolume] as defense-in-depth against exotic bind
//     mounts or mount points at the directory level.
//
// StagedWrite does not create missing parent directories. Callers are
// responsible for ensuring the parent exists; the sync pipeline (unit 13)
// creates the staging tree top-down before any StagedWrite calls.
//
// If any step fails, StagedWrite best-effort removes the temp file and
// returns the first error encountered. Partial writes are never visible
// at relPath.
func (r *Root) StagedWrite(relPath string, data []byte, mode fs.FileMode) (retErr error) {
	if err := ValidateRelPath(relPath); err != nil {
		return err
	}
	if err := r.DetectReparsePoint(relPath); err != nil && !errors.Is(err, fs.ErrNotExist) {
		return err
	}

	dir, base := path.Split(relPath)
	tempName, err := uniqueTempName(base)
	if err != nil {
		return fmt.Errorf("fsroot: generate temp name for %q: %w", relPath, err)
	}
	tempRel := dir + tempName

	f, err := r.inner.OpenFile(tempRel, os.O_CREATE|os.O_WRONLY|os.O_EXCL|oNoFollow, mode)
	if err != nil {
		return fmt.Errorf("fsroot: create staged temp %q: %w", tempRel, translateErr(err))
	}

	cleanup := func() {
		if retErr != nil {
			_ = r.inner.Remove(tempRel)
		}
	}
	defer cleanup()

	if _, err := f.Write(data); err != nil {
		_ = f.Close()
		return fmt.Errorf("fsroot: write %q: %w", tempRel, err)
	}
	if err := f.Sync(); err != nil {
		_ = f.Close()
		// Some filesystems (tmpfs on some kernels, specific NFS mounts)
		// legitimately refuse fsync with EINVAL. We do not currently
		// whitelist those; aienvs writes into user workspaces that are
		// expected to be on durable local filesystems. If this becomes
		// a real portability issue, gate here on errors.Is(err, syscall.EINVAL).
		return fmt.Errorf("fsroot: fsync %q: %w", tempRel, err)
	}
	if err := f.Close(); err != nil {
		return fmt.Errorf("fsroot: close %q: %w", tempRel, err)
	}

	if err := r.inner.Rename(tempRel, relPath); err != nil {
		return fmt.Errorf("fsroot: rename %q -> %q: %w", tempRel, relPath, translateRenameErr(err))
	}

	// Parent fsync is best-effort. Windows and many network filesystems
	// refuse to fsync a directory handle; we treat that as non-fatal
	// because the file data itself is already durable.
	_ = r.fsyncParent(dir)

	return nil
}

// fsyncParent opens the parent directory inside the root and calls Sync
// on it. Errors are returned to the caller but are treated as non-fatal
// by [Root.StagedWrite].
func (r *Root) fsyncParent(dir string) error {
	// dir may be "" (target at root) or ".../" from path.Split — normalize
	// to an os.Root-openable form.
	d := strings.TrimSuffix(dir, "/")
	if d == "" {
		d = "."
	}
	df, err := r.inner.Open(d)
	if err != nil {
		return err
	}
	defer func() { _ = df.Close() }()
	return df.Sync()
}

// uniqueTempName returns a deterministic-format but cryptographically
// unique temp file name for a staged write. The leading "." keeps the
// temp file out of default shell globs; the "aienv-stage" token lets
// aienvs identify its own orphaned temp files during crash recovery.
func uniqueTempName(base string) (string, error) {
	var randBuf [8]byte
	if _, err := rand.Read(randBuf[:]); err != nil {
		return "", err
	}
	return fmt.Sprintf(".%s.aienv-stage.%s.tmp", base, hex.EncodeToString(randBuf[:])), nil
}

// translateRenameErr maps EXDEV / ERROR_NOT_SAME_DEVICE to
// [ErrCrossVolume] and leaves other errors alone. Os-specific code in
// samefs_*.go fills this out; here we provide the portable fallback
// that recognizes the stdlib-level signal.
func translateRenameErr(err error) error {
	if err == nil {
		return nil
	}
	if isCrossDevice(err) {
		return fmt.Errorf("%w: %w", ErrCrossVolume, err)
	}
	return translateErr(err)
}

package fsroot

import (
	"errors"
	"fmt"
	"io/fs"
	"os"
	"path/filepath"
	"strings"
)

// Root is the aienvs-wrapped [os.Root] handle. It is the sole legitimate
// way for aienvs code to touch paths inside a user workspace.
//
// A Root is safe for concurrent use insofar as [os.Root] is: reads and
// writes may run in parallel, but the caller is responsible for
// serializing operations that must be ordered (for example, a rename
// that depends on a prior write).
type Root struct {
	inner *os.Root
	// absPath is the cleaned absolute path the root is scoped to.
	// Stored only so error messages can name the root without a
	// filesystem call; never used for lookups.
	absPath string
}

// Sentinel errors. Callers may inspect these with [errors.Is].
var (
	// ErrEscapesRoot is returned when a caller attempts an operation on
	// a path that [os.Root] refuses because it would escape the root.
	// We wrap [os.Root]'s raw error with this sentinel so higher layers
	// can branch on it without importing os/syscall.
	ErrEscapesRoot = errors.New("path escapes fsroot containment")

	// ErrCrossVolume is returned when a filesystem operation would cross
	// a filesystem boundary that aienvs refuses to traverse — notably a
	// rename across filesystems. The authoritative signal is the kernel
	// EXDEV / ERROR_NOT_SAME_DEVICE, not a statfs pre-flight.
	ErrCrossVolume = errors.New("cross-filesystem operation refused")

	// ErrIrregular is returned when a target is a reparse point, device
	// file, socket, or other irregular filesystem object that aienvs
	// refuses to write through.
	ErrIrregular = errors.New("target is an irregular filesystem object")

	// ErrUnsafeRelPath is returned when a caller supplies a relative
	// path that is syntactically unsafe (empty, absolute, or contains a
	// "..") before we even ask the kernel.
	ErrUnsafeRelPath = errors.New("unsafe relative path")
)

// OpenWorkspaceRoot opens dir as an [os.Root]-backed containment scope.
// dir must exist and be a directory; symlinks along dir are resolved in
// the usual OS manner (this is the one place we tolerate following
// symlinks, because it defines the boundary itself).
//
// The name is descriptive of the most common caller (workspace
// discovery). Nothing in [Root] actually requires the scope to be a
// workspace; unit 13 opens roots at each target's parent directory.
func OpenWorkspaceRoot(dir string) (*Root, error) {
	if dir == "" {
		return nil, fmt.Errorf("fsroot: %w: empty directory", ErrUnsafeRelPath)
	}
	abs, err := filepath.Abs(dir)
	if err != nil {
		return nil, fmt.Errorf("fsroot: resolve %q: %w", dir, err)
	}
	inner, err := os.OpenRoot(abs)
	if err != nil {
		return nil, fmt.Errorf("fsroot: open root %q: %w", abs, err)
	}
	return &Root{inner: inner, absPath: abs}, nil
}

// Close releases the underlying [os.Root] handle. It is safe to call
// Close on a nil Root.
func (r *Root) Close() error {
	if r == nil || r.inner == nil {
		return nil
	}
	return r.inner.Close()
}

// Path returns the absolute, cleaned directory the root is scoped to.
// This is informational; callers must never feed Path back into a
// filesystem call — use the [os.Root] methods on Inner instead.
func (r *Root) Path() string {
	if r == nil {
		return ""
	}
	return r.absPath
}

// Inner exposes the wrapped [os.Root] for callers that need operations
// fsroot does not yet wrap. New call sites should prefer adding a
// method here over reaching through Inner, so the containment invariants
// stay in one place.
func (r *Root) Inner() *os.Root {
	if r == nil {
		return nil
	}
	return r.inner
}

// Lstat is a convenience wrapper around [os.Root.Lstat] that translates
// the raw [os.Root] escape error into [ErrEscapesRoot].
func (r *Root) Lstat(relPath string) (fs.FileInfo, error) {
	if err := ValidateRelPath(relPath); err != nil {
		return nil, err
	}
	fi, err := r.inner.Lstat(relPath)
	if err != nil {
		return nil, translateErr(err)
	}
	return fi, nil
}

// Stat wraps [os.Root.Stat] with the same error translation as Lstat.
func (r *Root) Stat(relPath string) (fs.FileInfo, error) {
	if err := ValidateRelPath(relPath); err != nil {
		return nil, err
	}
	fi, err := r.inner.Stat(relPath)
	if err != nil {
		return nil, translateErr(err)
	}
	return fi, nil
}

// ValidateRelPath rejects relative paths that are structurally unsafe
// before they reach the kernel. [os.Root] also refuses them, but an
// early sentinel error makes test failures and log lines easier to
// read.
//
// A valid relPath:
//   - is non-empty
//   - is not absolute
//   - is not "." and does not start with ".." or contain a ".." segment
//   - is forward-slash normalized (backslashes are allowed and
//     normalized away here so Windows callers can pass either)
func ValidateRelPath(relPath string) error {
	if relPath == "" {
		return fmt.Errorf("%w: empty", ErrUnsafeRelPath)
	}
	if filepath.IsAbs(relPath) {
		return fmt.Errorf("%w: absolute path %q", ErrUnsafeRelPath, relPath)
	}
	cleaned := filepath.ToSlash(relPath)
	for _, seg := range strings.Split(cleaned, "/") {
		switch seg {
		case "", ".":
			// Allowed in intermediate positions; Clean would strip them.
		case "..":
			return fmt.Errorf("%w: contains %q: %q", ErrUnsafeRelPath, "..", relPath)
		}
	}
	return nil
}

// translateErr maps raw os.Root containment errors into sentinel errors
// the rest of aienvs can branch on. Anything we do not recognize passes
// through unchanged so callers still see the underlying syscall detail.
func translateErr(err error) error {
	if err == nil {
		return nil
	}
	var pathErr *os.PathError
	if errors.As(err, &pathErr) {
		// os.Root returns a PathError wrapping an opaque "path escapes
		// from parent" error; the stable way to detect it is the
		// package's exported os.ErrInvalid plus a message match. The
		// more robust path is to check the specific syscall error on
		// POSIX, but we stay portable by leaving unrecognized paths
		// alone and only up-converting the clear escape cases.
		if strings.Contains(pathErr.Err.Error(), "path escapes") ||
			strings.Contains(pathErr.Err.Error(), "outside the root") {
			return fmt.Errorf("%w: %w", ErrEscapesRoot, pathErr)
		}
	}
	return err
}

