			return nil, fmt.Errorf("update trusted_sha: %w", err)
		}
	}

	out := []byte(file.String())
	// goccy's ast.File.String() does not guarantee a trailing newline;
	// normalize so subsequent hand-edits and line-diff tools behave.
	if len(out) > 0 && out[len(out)-1] != '\n' {
		out = append(out, '\n')
	}
	return out, nil
}

// WriteTrustedSHA is the `aienvs trust pin` subcommand's writer: it
// updates only `trusted_sha:` and leaves `canonical.commit:` alone.
// See plan decision #9.
func WriteTrustedSHA(orig []byte, trustedSHA string) ([]byte, error) {
	return WriteResolvedSHA(orig, "", trustedSHA)
}

// WriteFile atomically writes content to the manifest file at path,
// using the fsroot StagedWrite primitive so the write is crash-safe
// and contained. path may be absolute or relative to cwd.
//
// Permissions match typical YAML config: 0o644. The manifest is not
// secret — it sits in the repo alongside committed sources.
func WriteFile(path string, content []byte) error {
	abs, err := filepath.Abs(path)
	if err != nil {
		return fmt.Errorf("resolve %q: %w", path, err)
	}
	parent := filepath.Dir(abs)
	base := filepath.Base(abs)

	root, err := fsroot.OpenWorkspaceRoot(parent)
	if err != nil {
		return fmt.Errorf("open parent %q: %w", parent, err)
	}
	defer func() { _ = root.Close() }()

	return root.StagedWrite(base, content, fs.FileMode(0o644))
}

// replaceScalar locates path inside file and replaces its scalar value
// with the given string. If path does not resolve to an existing node,
// ErrKeyMissing is returned.
func replaceScalar(file *parserFile, path, value string) error {
	p, err := yaml.PathString(path)
	if err != nil {
		return fmt.Errorf("bad path %q: %w", path, err)
	}
	// Probe existence first so we can distinguish "missing" from
	// "replace failed" cleanly.
	if _, err := p.FilterFile(file); err != nil {
		return fmt.Errorf("%w: %s", ErrKeyMissing, strings.TrimSpace(err.Error()))
	}
	if err := p.ReplaceWithReader(file, strings.NewReader(value)); err != nil {
		return fmt.Errorf("replace %q: %w", path, err)
	}
	return nil
}

// parserFile is a local alias that lets us avoid importing goccy's ast
// package just for the *ast.File type in function signatures. goccy
// re-exports it implicitly through yaml.PathString consumers, but we
// need the direct type for the signature of replaceScalar.
//
// Using the re-export keeps the public surface of this package from
// leaking the ast dependency and matches the layering the plan calls
// for in unit 2.
type parserFile = parserFileAlias

