	m, err := loadFixture(t, "valid-minimal.yaml", manifest.LoadOptions{})
	if err != nil {
		t.Fatalf("load: %v", err)
	}
	if m.Version != 1 {
		t.Errorf("version = %d, want 1", m.Version)
