	if _, err := manifest.LoadFile(path, manifest.LoadOptions{}); err != nil {
		t.Errorf("LoadFile after WriteFile: %v", err)
	}
}

func TestWriteFile_OverwriteAtomic(t *testing.T) {
	dir := t.TempDir()
