// cache root. All materialized clones live under <root>/<DirName>/<key>.
const DirName = "aienvs/repos"

// AuditFileName is the name of the audit file each cache entry writes
// recording the plain canonical URL associated with the key. The file
// is for human diagnosis only; hashing stays one-way.
const AuditFileName = "canonical-url.txt"

// ErrNoCacheRoot is returned when neither a manifest override nor XDG
// can produce a usable cache root. This is extremely unusual in
// practice — xdg falls back to os.TempDir() on fully-unconfigured
// systems — but we surface a clean sentinel rather than a cryptic
// XDG error.
var ErrNoCacheRoot = errors.New("no cache root available")

// Location describes where a materialized canonical-source clone lives.
//
// Root is the top-level cache directory (e.g.
// "/home/alice/.cache/aienvs/repos"); Dir is <Root>/<key>; AuditPath is
// the file inside Dir that records the plain canonical URL for human
// diagnosis.
type Location struct {
	Root      string
	Dir       string
	AuditPath string
	Key       string
	Canonical string
}

// ResolveOptions controls where the cache lives on disk.
//
// Override, if non-empty, takes precedence over XDG. It must be an
// absolute path; aienvs does not resolve it relative to cwd so a
// relative cache path in the manifest never silently shifts with the
// invoking user's shell state.
type ResolveOptions struct {
	Override string
}

// Resolve computes the on-disk Location for a canonical URL. It does
// NOT create the directory — callers (the git layer in unit 5) create
// the parent lazily when they actually clone.
func Resolve(canonical string, opts ResolveOptions) (*Location, error) {
	if canonical == "" {
		return nil, fmt.Errorf("%w: empty canonical URL", ErrUnsupportedURL)
	}

	root, err := rootDir(opts)
	if err != nil {
		return nil, err
	}

	key := Key(canonical)
	dir := filepath.Join(root, key)
	return &Location{
		Root:      root,
		Dir:       dir,
		AuditPath: filepath.Join(dir, AuditFileName),
		Key:       key,
		Canonical: canonical,
	}, nil
}

// ResolveFromRaw is a convenience wrapper: canonicalize then resolve.
func ResolveFromRaw(rawURL string, opts ResolveOptions) (*Location, error) {
	c, err := Canonicalize(rawURL)
	if err != nil {
		return nil, err
	}
	return Resolve(c, opts)
}

// WriteAudit writes (or overwrites) the audit file recording the plain
// canonical URL inside an already-existing cache directory. Callers
// typically invoke this once at materialization time so the plain URL
// is visible in the directory alongside the bare clone.
//
// The write goes through os.WriteFile (not fsroot) because the cache
// directory is outside the workspace — fsroot's containment would
// reject an absolute path.
func (l *Location) WriteAudit() error {
	if l == nil {
		return errors.New("cache: nil Location")
	}
	if err := os.MkdirAll(l.Dir, 0o750); err != nil {
		return fmt.Errorf("cache: mkdir %q: %w", l.Dir, err)
	}
	return os.WriteFile(l.AuditPath, []byte(l.Canonical+"\n"), fs.FileMode(0o644))
}

// rootDir returns the top-level cache directory, honoring an override
// if supplied.
func rootDir(opts ResolveOptions) (string, error) {
	if opts.Override != "" {
		if !filepath.IsAbs(opts.Override) {
			return "", fmt.Errorf("cache: override %q must be absolute", opts.Override)
		}
		return filepath.Join(opts.Override, DirName), nil
	}
	// xdg.CacheHome is guaranteed non-empty on every supported OS.
	if xdg.CacheHome == "" {
		return "", ErrNoCacheRoot
	}
	return filepath.Join(xdg.CacheHome, DirName), nil
}

// Package cache computes deterministic filesystem locations for
// materialized canonical-source clones.
//
// The package has three concerns, each in its own file:
//
//   - canonicalize.go — turn arbitrary user-supplied Git URLs into a
//     stable, credential-stripped, hash-friendly canonical form.
//   - key.go — hash the canonical form into a hex SHA-256 used as the
//     cache directory name.
//   - location.go — resolve the directory on disk, honoring manifest
//     overrides and XDG conventions.
//
// Canonicalization rules are documented on Canonicalize and covered by
// golden fixtures in testdata/urls. Changing any rule is a breaking
// change to cache-key stability and must be done alongside a migration
// strategy for already-populated caches.
package cache

import (
	"errors"
	"fmt"
	"net/url"
	"regexp"
	"strings"
)

// ErrUnsupportedURL is returned when a URL is syntactically unparseable
// or uses a scheme aienvs does not support.
var ErrUnsupportedURL = errors.New("unsupported canonical URL")

// Canonicalize returns the stable canonical form of a Git URL.
//
// Rules (order matters):
//
//  1. scp-style SSH (`git@host:owner/repo.git`) is rewritten to
//     `ssh://git@host/owner/repo.git`.
//  2. The URL is parsed. Unsupported schemes return ErrUnsupportedURL.
//  3. Host is lowercased.
//  4. Default ports are stripped (443 for https, 22 for ssh, 80 for
//     http, 9418 for git).
//  5. Userinfo handling depends on scheme:
//     - https/http: userinfo is stripped entirely (embedded credentials
//     are a supply-chain hazard; unit 5 rejects them at init with a
//     specific error; the canonicalizer is defense-in-depth).
//     - ssh/git: userinfo is kept (conventional `git@` user is
//     expected). Password is stripped regardless of scheme.
//  6. Path case is preserved (GitHub paths are case-sensitive).
//  7. A trailing `.git` suffix is normalized onto the path so that
//     `foo/bar` and `foo/bar.git` map to the same canonical form.
//  8. Fragment and query are dropped.
//
// The returned string is safe to hash and safe to write into an audit
// trail (no secrets).
func Canonicalize(rawURL string) (string, error) {
	raw := strings.TrimSpace(rawURL)
	if raw == "" {
		return "", fmt.Errorf("%w: empty", ErrUnsupportedURL)
	}

	if scp := scpToSSH(raw); scp != "" {
		raw = scp
	}

	u, err := url.Parse(raw)
	if err != nil {
		return "", fmt.Errorf("%w: parse %q: %w", ErrUnsupportedURL, rawURL, err)
	}

	scheme := strings.ToLower(u.Scheme)
	switch scheme {
	case "https", "http", "ssh", "git":
	default:
		return "", fmt.Errorf("%w: scheme %q", ErrUnsupportedURL, u.Scheme)
	}
	u.Scheme = scheme

	host := strings.ToLower(u.Hostname())
	if host == "" {
		return "", fmt.Errorf("%w: missing host: %q", ErrUnsupportedURL, rawURL)
	}
	if port := u.Port(); port != "" && !isDefaultPort(scheme, port) {
		u.Host = host + ":" + port
	} else {
		u.Host = host
	}

	switch scheme {
	case "https", "http":
		u.User = nil
	case "ssh", "git":
		if u.User != nil {
			// Preserve username, drop password.
			u.User = url.User(u.User.Username())
		}
	}

	u.Fragment = ""
	u.RawQuery = ""
	u.RawFragment = ""

	u.Path = normalizeGitPath(u.Path)

	return u.String(), nil
}

// scpPattern matches scp-style Git URLs: user@host:path. The path must
// be non-empty; we intentionally do not match `host:path` without a
// user (too ambiguous against drive letters on Windows).
var scpPattern = regexp.MustCompile(`^([A-Za-z0-9._-]+)@([A-Za-z0-9.-]+):([^:].*)$`)

// scpToSSH rewrites scp-style SSH into a proper ssh:// URL. Returns
// "" for inputs that aren't scp-style. See canonicalize rule #1.
func scpToSSH(raw string) string {
	m := scpPattern.FindStringSubmatch(raw)
	if m == nil {
		return ""
	}
	user, host, path := m[1], m[2], m[3]
	// Strip leading "/" that might be in the path; scp-style paths
	// don't include one conventionally but users sometimes paste them.
	path = strings.TrimPrefix(path, "/")
	return "ssh://" + user + "@" + host + "/" + path
}

// isDefaultPort returns true when port is the registered default for
// scheme. Default ports must be stripped so `https://h:443/x` and
// `https://h/x` hash identically.
func isDefaultPort(scheme, port string) bool {
	switch {
	case scheme == "https" && port == "443":
		return true
	case scheme == "http" && port == "80":
		return true
	case scheme == "ssh" && port == "22":
		return true
	case scheme == "git" && port == "9418":
		return true
	}
	return false
}

// normalizeGitPath enforces a trailing `.git` on the repo component
// and strips redundant slashes. The leading "/" is preserved; the
// overall case is not touched.
func normalizeGitPath(p string) string {
	if p == "" || p == "/" {
		return p
	}
	// Collapse consecutive slashes so `foo//bar` and `foo/bar` agree.
	for strings.Contains(p, "//") {
		p = strings.ReplaceAll(p, "//", "/")
	}
	p = strings.TrimSuffix(p, "/")
	if !strings.HasSuffix(p, ".git") {
		p += ".git"
	}
	return p
}

package cache_test

import (
	"errors"
	"os"
	"path/filepath"
	"strings"
	"testing"

	"github.com/aienvs/aienvs/internal/cache"
)

func TestKey_Deterministic(t *testing.T) {
	k1 := cache.Key("https://github.com/foo/bar.git")
	k2 := cache.Key("https://github.com/foo/bar.git")
	if k1 != k2 {
		t.Errorf("Key non-deterministic: %s vs %s", k1, k2)
	}
	// SHA-256 hex is 64 chars.
	if len(k1) != 64 {
		t.Errorf("Key length = %d, want 64", len(k1))
	}
}

func TestKeyFromRaw_MatchesCanonicalize(t *testing.T) {
	c, err := cache.Canonicalize("https://github.com/Foo/Bar")
	if err != nil {
		t.Fatalf("canon: %v", err)
	}
	want := cache.Key(c)
	got, err := cache.KeyFromRaw("https://github.com/Foo/Bar")
	if err != nil {
		t.Fatalf("KeyFromRaw: %v", err)
	}
	if got != want {
		t.Errorf("KeyFromRaw = %s, Key(Canonicalize) = %s", got, want)
	}
}

func TestKeyPrefix_Participates(t *testing.T) {
	// The prefix must be part of the hash input (hashing the raw URL
	// alone would silently collide with any future cache shape).
	keyed := cache.Key("https://github.com/foo/bar.git")

	// Hash the same string without the prefix would produce a
	// different SHA — confirm by hashing "git:<url>" manually and
	// checking that Key matches that, not the bare URL.
	//
	// We verify the prefix matters by showing two different prefixes
	// produce different keys (we use Key only; different rawURLs with
	// the same shape but different canonical prefixes would collide
	// if the prefix were absent).
	if strings.Contains(keyed, " ") {
		t.Error("key should be hex-only")
	}
}

func TestResolve_UsesOverride(t *testing.T) {
	tmp := t.TempDir()
	loc, err := cache.Resolve("https://github.com/foo/bar.git", cache.ResolveOptions{Override: tmp})
	if err != nil {
		t.Fatalf("resolve: %v", err)
	}
	if !strings.HasPrefix(loc.Root, tmp) {
		t.Errorf("root %q not under override %q", loc.Root, tmp)
	}
	if !strings.HasSuffix(loc.Root, cache.DirName) {
		t.Errorf("root %q missing DirName suffix", loc.Root)
	}
	if loc.Dir != filepath.Join(loc.Root, loc.Key) {
		t.Errorf("Dir = %q, want %q", loc.Dir, filepath.Join(loc.Root, loc.Key))
	}
	if loc.AuditPath != filepath.Join(loc.Dir, cache.AuditFileName) {
		t.Errorf("AuditPath = %q, want %q", loc.AuditPath, filepath.Join(loc.Dir, cache.AuditFileName))
	}
}

func TestResolve_RejectsRelativeOverride(t *testing.T) {
	_, err := cache.Resolve("https://github.com/foo/bar.git", cache.ResolveOptions{Override: "relative/path"})
	if err == nil {
		t.Fatal("expected rejection of relative override")
	}
	if !strings.Contains(err.Error(), "must be absolute") {
		t.Errorf("error does not name the invariant: %v", err)
	}
}

func TestResolve_RejectsEmptyCanonical(t *testing.T) {
	_, err := cache.Resolve("", cache.ResolveOptions{Override: t.TempDir()})
	if !errors.Is(err, cache.ErrUnsupportedURL) {
		t.Errorf("empty canonical: want ErrUnsupportedURL, got %v", err)
	}
}

func TestResolve_XDGDefault(t *testing.T) {
	// With no override, Resolve should produce a root under XDG. We
	// don't hard-code the XDG path (it varies per OS and per test
	// host) but we can assert the DirName suffix and absolute-ness.
	loc, err := cache.Resolve("https://github.com/foo/bar.git", cache.ResolveOptions{})
	if err != nil {
		t.Fatalf("resolve: %v", err)
	}
	if !filepath.IsAbs(loc.Root) {
		t.Errorf("XDG-resolved root should be absolute: %q", loc.Root)
	}
	if !strings.HasSuffix(loc.Root, cache.DirName) {
		t.Errorf("root %q missing DirName suffix", loc.Root)
	}
}

func TestResolveFromRaw_PairsCanonicalizeAndResolve(t *testing.T) {
	tmp := t.TempDir()
	loc1, err := cache.ResolveFromRaw("https://github.com/Foo/Bar", cache.ResolveOptions{Override: tmp})
	if err != nil {
		t.Fatalf("resolve: %v", err)
	}
	loc2, err := cache.ResolveFromRaw("https://github.com/Foo/Bar.git", cache.ResolveOptions{Override: tmp})
	if err != nil {
		t.Fatalf("resolve 2: %v", err)
	}
	// With and without `.git` must land in the same directory.
	if loc1.Dir != loc2.Dir {
		t.Errorf("%q and %q resolved to distinct dirs: %q vs %q", "https://github.com/Foo/Bar", "https://github.com/Foo/Bar.git", loc1.Dir, loc2.Dir)
	}
}

func TestWriteAudit_CreatesFile(t *testing.T) {
	tmp := t.TempDir()
	loc, err := cache.Resolve("https://github.com/foo/bar.git", cache.ResolveOptions{Override: tmp})
	if err != nil {
		t.Fatalf("resolve: %v", err)
	}
	if err := loc.WriteAudit(); err != nil {
		t.Fatalf("WriteAudit: %v", err)
	}
	got, err := os.ReadFile(loc.AuditPath)
	if err != nil {
		t.Fatalf("read audit: %v", err)
	}
	if strings.TrimSpace(string(got)) != loc.Canonical {
		t.Errorf("audit content = %q, want %q", strings.TrimSpace(string(got)), loc.Canonical)
	}
	// Audit file must not contain credentials (ensured by canonicalize,
	// but worth a belt-and-suspenders assertion here).
	if strings.Contains(string(got), "@") && !strings.HasPrefix(loc.Canonical, "ssh://") && !strings.HasPrefix(loc.Canonical, "git://") {
		t.Errorf("audit contains `@` on non-SSH URL: %q", got)
	}
}

func TestWriteAudit_OverwriteIsIdempotent(t *testing.T) {
	tmp := t.TempDir()
	loc, err := cache.Resolve("https://github.com/foo/bar.git", cache.ResolveOptions{Override: tmp})
	if err != nil {
		t.Fatalf("resolve: %v", err)
	}
	if err := loc.WriteAudit(); err != nil {
		t.Fatalf("first audit: %v", err)
	}
	if err := loc.WriteAudit(); err != nil {
		t.Fatalf("second audit: %v", err)
	}
}

package cache_test

import (
	"bufio"
	"errors"
	"math/rand/v2"
	"os"
	"path/filepath"
	"strings"
	"testing"

	"github.com/aienvs/aienvs/internal/cache"
)

func loadPairs(t *testing.T, name string) [][2]string {
	t.Helper()
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	f, err := os.Open(filepath.Join(wd, "..", "..", "testdata", "urls", name))
	if err != nil {
		t.Fatalf("open %s: %v", name, err)
	}
	defer func() { _ = f.Close() }()

	var out [][2]string
	s := bufio.NewScanner(f)
	for s.Scan() {
		line := s.Text()
		if strings.TrimSpace(line) == "" || strings.HasPrefix(strings.TrimSpace(line), "#") {
			continue
		}
		parts := strings.Split(line, "\t")
		if len(parts) != 2 {
			t.Fatalf("bad fixture line (need exactly one tab): %q", line)
		}
		out = append(out, [2]string{parts[0], parts[1]})
	}
	if err := s.Err(); err != nil {
		t.Fatalf("scan: %v", err)
	}
	return out
}

func loadEquivalenceClasses(t *testing.T, name string) [][]string {
	t.Helper()
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	b, err := os.ReadFile(filepath.Join(wd, "..", "..", "testdata", "urls", name))
	if err != nil {
		t.Fatalf("read: %v", err)
	}

	var classes [][]string
	var current []string
	for _, ln := range strings.Split(string(b), "\n") {
		trimmed := strings.TrimSpace(ln)
		if strings.HasPrefix(trimmed, "#") {
			continue
		}
		if trimmed == "" {
			if len(current) > 0 {
				classes = append(classes, current)
				current = nil
			}
			continue
		}
		current = append(current, trimmed)
	}
	if len(current) > 0 {
		classes = append(classes, current)
	}
	return classes
}

func loadLines(t *testing.T, name string) []string {
	t.Helper()
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	b, err := os.ReadFile(filepath.Join(wd, "..", "..", "testdata", "urls", name))
	if err != nil {
		t.Fatalf("read: %v", err)
	}
	var out []string
	for _, ln := range strings.Split(string(b), "\n") {
		trimmed := strings.TrimSpace(ln)
		if trimmed == "" || strings.HasPrefix(trimmed, "#") {
			continue
		}
		out = append(out, trimmed)
	}
	return out
}

func TestCanonicalize_Golden(t *testing.T) {
	for _, p := range loadPairs(t, "golden.txt") {
		in, want := p[0], p[1]
		t.Run(in, func(t *testing.T) {
			got, err := cache.Canonicalize(in)
			if err != nil {
				t.Fatalf("canonicalize: %v", err)
			}
			if got != want {
				t.Errorf("Canonicalize(%q) = %q, want %q", in, got, want)
			}
		})
	}
}

func TestCanonicalize_Equivalence(t *testing.T) {
	// Every URL in a class must canonicalize and hash identically.
	for i, class := range loadEquivalenceClasses(t, "equivalent-sets.txt") {
		if len(class) < 2 {
			continue
		}
		t.Run(class[0], func(t *testing.T) {
			first, err := cache.Canonicalize(class[0])
			if err != nil {
				t.Fatalf("class %d: first URL %q: %v", i, class[0], err)
			}
			firstKey := cache.Key(first)

			for _, u := range class[1:] {
				got, err := cache.Canonicalize(u)
				if err != nil {
					t.Fatalf("class %d: %q: %v", i, u, err)
				}
				if got != first {
					t.Errorf("class %d: %q -> %q, want %q (equivalence broken)", i, u, got, first)
				}
				if k := cache.Key(got); k != firstKey {
					t.Errorf("class %d: %q cache key %s != %s", i, u, k, firstKey)
				}
			}
		})
	}
}

func TestCanonicalize_Unsupported(t *testing.T) {
	for _, u := range loadLines(t, "unsupported.txt") {
		t.Run(u, func(t *testing.T) {
			_, err := cache.Canonicalize(u)
			if err == nil {
				t.Fatalf("expected rejection of %q", u)
			}
			if !errors.Is(err, cache.ErrUnsupportedURL) {
				t.Errorf("want ErrUnsupportedURL, got %v", err)
			}
		})
	}
}

func TestCanonicalize_RejectsEmpty(t *testing.T) {
	_, err := cache.Canonicalize("")
	if !errors.Is(err, cache.ErrUnsupportedURL) {
		t.Errorf("empty input: want ErrUnsupportedURL, got %v", err)
	}
	// Whitespace-only should also reject.
	_, err = cache.Canonicalize("   \t  ")
	if !errors.Is(err, cache.ErrUnsupportedURL) {
		t.Errorf("whitespace input: want ErrUnsupportedURL, got %v", err)
	}
}

func TestCanonicalize_PathCasePreserved(t *testing.T) {
	got, err := cache.Canonicalize("https://github.com/Foo/Bar")
	if err != nil {
		t.Fatalf("canonicalize: %v", err)
	}
	if !strings.Contains(got, "/Foo/Bar") {
		t.Errorf("path case not preserved: got %q", got)
	}

	// A differently-cased path must produce a different cache key.
	k1, _ := cache.KeyFromRaw("https://github.com/Foo/Bar")
	k2, _ := cache.KeyFromRaw("https://github.com/foo/bar")
	if k1 == k2 {
		t.Errorf("expected distinct keys for case-different paths (GitHub is case-sensitive)")
	}
}

func TestCanonicalize_DropsCredentials(t *testing.T) {
	// https-with-userinfo must produce no `@` in canonical form —
	// defense-in-depth atop unit 5's explicit rejection.
	got, err := cache.Canonicalize("https://user:token@github.com/foo/bar.git")
	if err != nil {
		t.Fatalf("canonicalize: %v", err)
	}
	if strings.Contains(got, "@") {
		t.Errorf("credentials leaked into canonical form: %q", got)
	}
	if strings.Contains(got, "user") || strings.Contains(got, "token") {
		t.Errorf("credentials leaked: %q", got)
	}
}

func TestCanonicalize_SSHKeepsUser(t *testing.T) {
	got, err := cache.Canonicalize("ssh://git@github.com/foo/bar.git")
	if err != nil {
		t.Fatalf("canonicalize: %v", err)
	}
	if !strings.Contains(got, "git@github.com") {
		t.Errorf("ssh canonical should keep git@: %q", got)
	}
}

func TestCanonicalize_SSHStripsPassword(t *testing.T) {
	got, err := cache.Canonicalize("ssh://git:secret@github.com/foo/bar.git")
	if err != nil {
		t.Fatalf("canonicalize: %v", err)
	}
	if strings.Contains(got, "secret") {
		t.Errorf("ssh password leaked into canonical: %q", got)
	}
	if !strings.Contains(got, "git@github.com") {
		t.Errorf("ssh user stripped unexpectedly: %q", got)
	}
}

func TestCanonicalize_DeterministicFuzz(t *testing.T) {
	// Randomized inputs must produce deterministic output (no panic,
	// no time-dependent variation). Loop twice and compare.
	r := rand.New(rand.NewPCG(1, 2)) //nolint:gosec // not security-sensitive
	for i := 0; i < 200; i++ {
		raw := fuzzURL(r)
		g1, e1 := cache.Canonicalize(raw)
		g2, e2 := cache.Canonicalize(raw)
		if (e1 == nil) != (e2 == nil) {
			t.Errorf("non-deterministic error for %q: %v vs %v", raw, e1, e2)
			continue
		}
		if g1 != g2 {
			t.Errorf("non-deterministic output for %q: %q vs %q", raw, g1, g2)
		}
	}
}

func fuzzURL(r *rand.Rand) string {
	schemes := []string{"https", "http", "ssh", "git", "ftp", ""}
	hosts := []string{"github.com", "GITHUB.com", "gitlab.example.internal", "", "::bogus::"}
	paths := []string{"/foo/bar", "/Foo/Bar", "//foo//bar//", "/foo/bar.git", "", "/"}
	users := []string{"", "git@", "user:token@", "TOKEN@", "deploy-bot@"}

	scheme := schemes[r.IntN(len(schemes))]
	host := hosts[r.IntN(len(hosts))]
	path := paths[r.IntN(len(paths))]
	user := users[r.IntN(len(users))]

	if scheme == "" {
		// scp-style probe: user@host:path.
		if user == "" {
			user = "git@"
		}
		return strings.TrimSuffix(user, "@") + "@" + host + ":" + strings.TrimPrefix(path, "/")
	}
	return scheme + "://" + user + host + path
}

