```go
linfo, err := os.Lstat(manifestPath)
if errors.Is(err, fs.ErrNotExist) {
    // truly no entry here — continue walk
    continue
}
if err != nil {
    return nil, fmt.Errorf("workspace: lstat %q: %w", manifestPath, err)
}

if linfo.Mode()&os.ModeSymlink != 0 {
    // follow the symlink
    info, err := os.Stat(manifestPath)
    if errors.Is(err, fs.ErrNotExist) {
        return nil, fmt.Errorf("%w: %q is a dangling symlink", ErrManifestNotRegular, manifestPath)
    }
    if err != nil {
        return nil, fmt.Errorf("workspace: stat %q: %w", manifestPath, err)
    }
    if !info.Mode().IsRegular() {
        return nil, fmt.Errorf("%w: %q is a symlink to %s", ErrManifestNotRegular, manifestPath, modeLabel(info.Mode()))
    }
    // found — symlink to regular file, treat as found (existing intentional behavior)
    return foundResult(manifestPath), nil
}

if !linfo.Mode().IsRegular() {
    return nil, fmt.Errorf("%w: %q is %s", ErrManifestNotRegular, manifestPath, modeLabel(linfo.Mode()))
}
// regular file — found
return foundResult(manifestPath), nil
```

